    useEffect(() => {
        // var children = document.querySelectorAll(".styles_navLinks__38tON ul li a");
        // if(isClicked)
        // {

        document.querySelectorAll("html body .styles_navLinks__38tON ul li a")[0].addEventListener('click', (e) => {

            window.scrollTo({
                top: document.getElementById('project').getBoundingClientRect().top +  window.pageYOffset - 55,
                behavior: 'smooth',
            });

            }

        );
        document.querySelectorAll("html body .styles_navLinks__38tON ul li a")[1].addEventListener('click', (e) => {

                window.scrollTo({
                    top: document.getElementById('aboutme').getBoundingClientRect().top +  window.pageYOffset - 55,
                    behavior: 'smooth',
                });

            }

        );
            // document.querySelectorAll("html body .styles_navLinks__38tON ul li a").forEach(function (child) {
